var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국 재건 도시 ARC-PW1 외곽</color>","JPN":"<color=#ffd34c>管理局再建都市ARC-PW1の外郭</color>","ENG":"<color=#ffd34c>Administration Rebuilt City ARC-PW1 Outskirts</color>","TWN":"<color=#ffd34c>管理局重建城市 ARC-PW1近郊</color>","SCN":"<color=#ffd34c>管理局重建城市 ARC-PW1 外围</color>","DEU":"<color=#ffd34c>Administration Rebuilt City ARC-PW1 Outskirts</color>","FRA":"<color=#ffd34c>Administration Rebuilt City ARC-PW1 Outskirts</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이 근처에서 냄새가 나는데…….","JPN":"この辺りからだ……","ENG":"I smell something around here...","TWN":"這附近有味道……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"지독한 <color=#ffd34c>악령</color>의 냄새가…….","JPN":"<color=#ffd34c>悪霊</color>のひどい匂いがする……","ENG":"A foul stench of an <color=#ffd34c>evil spirit</color>...","TWN":"強烈的<color=#ffd34c>惡靈</color>的氣味……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"여기구나!","JPN":"ここか！","ENG":"Found it!","TWN":"在這裡啊！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이 녀석이 마지막인가?","JPN":"こいつが最後か？","ENG":"Is this the last one?","TWN":"這傢伙是最後一個了吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"침식 쐐기도 파괴했고……","JPN":"侵食楔も破壊しましたし……","ENG":"I've destroyed the Corrupted Wedge...","TWN":"侵蝕釘也破壞了……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이제 악령들이 여러분을 괴롭힐 일은 없을 겁니다.","JPN":"もう悪霊が皆さんを苦しめることはないでしょう。","ENG":"Now, these evil spirits won't trouble you anymore.","TWN":"現在惡靈們不會再來騷擾你們了。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"안심하시길.","JPN":"ご安心ください。","ENG":"You can rest easy.","TWN":"請放心。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"감사합니다. 수녀님. 이 은혜를 어찌 갚아야 할지…….","JPN":"ありがとうございます、シスター。このご恩に報いるにはどうすれば……","ENG":"Thank you, Sister. I don't know how we could ever repay you...","TWN":"謝謝你，修女。我真不知道該如何報答這份恩情……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"해야 할 일을 했을 뿐이죠.","JPN":"己の役目を果たしただけです。","ENG":"I only did what needed to be done.","TWN":"我只是做了我該做的事而已。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"하지만 여러분들의 호의를 거절하는 건 예의가 아닌 법.","JPN":"ですが、みなさんのご厚意を断るのも失礼でしょう。","ENG":"But refusing a token of gratitude wouldn't be polite.","TWN":"但是拒絕大家的好意是不禮貌的。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"자, 이건 악령이 깃든 땅을 정화하는 성수예요.","JPN":"どうぞ、こちらを。悪霊が巣くう地を浄化する聖水です。","ENG":"Here, this is holy water to cleanse the land of evil spirits.","TWN":"這是可以淨化惡靈的淨水。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"땅에 성수가 많이 스며들수록 악령들이 쉽게 접근하지 못할 겁니다.","JPN":"地に染み込んだ聖水が多くなるほど、悪霊がたやすく近寄れなくなります。","ENG":"The more you pour into the ground, the harder it will be for them to return.","TWN":"淨水滲入土地越多，惡靈就越難靠近。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"물론, 주님의 영험함을 담은 진품이죠.","JPN":"もちろん、主の神聖な力が込められている本物ですよ。","ENG":"And of course, it's the real deal with the Lord's power.","TWN":"當然，這可是蘊含了主的神奇力量的真品。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"직접 세례를 받은 성수라는 겁니까?","JPN":"直接洗礼を受けた聖水ということですか？","ENG":"You mean... it's been personally blessed?","TWN":"這是直接受洗的淨水嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"네. 직접 마셔도 효능이 있답니다.","JPN":"はい。飲んでも効果があるんですよ。","ENG":"Yes. You can even drink it for its restorative effects.","TWN":"是的，直接喝也有效果。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"무려, 지친 몸에 활력을 불어넣게 되죠.","JPN":"なんと、疲れた体に活力を吹き込んでくれるのです。","ENG":"In fact, it'll help reinvigorate a tired body.","TWN":"還能給疲憊的身體注入活力呢。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"지친 몸에 활력을…….","JPN":"疲れた体に活力を……","ENG":"Reinvigorate a tired body...","TWN":"能為疲憊的身體注入活力……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"안 그래도 요즘 부쩍 몸이 무거워진 것 같았어.","JPN":"そういえば、最近体が重く感じるんだよな。","ENG":"Come to think of it, I have been feeling sluggish lately.","TWN":"最近確實感覺身體越來越沉重了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"저요! 그 성수, 제가 10병 사겠습니다!","JPN":"あの！　その聖水10本買います！","ENG":"I'll take ten bottles!","TWN":"那淨水，我要買10瓶！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"저도 살게요!","JPN":"私も買います！","ENG":"I'll buy some too!","TWN":"我也要買！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};